INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q4, 'en', 'Which state or union territory best represents the place where you have lived for a significant part of your life?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q4, 'hi', 'लेकिन किस राज्य या केंद्रशासित प्रदेश ने उस स्थान का सबसे अच्छा प्रतिनिधित्व किया है जहाँ आप अपना अधिकांश जीवन रहे हैं?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q4, 'bn', 'কোন রাজ্য বা কেন্দ্রশাসিত অঞ্চলটি সেই জায়গাটিকে সবচেয়ে ভালোভাবে উপস্থাপন করে যেখানে আপনি আপনার জীবনের একটি উল্লেখযোগ্য অংশে বসবাস করেছেন?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q4, 'gu', 'કયું રાજ્ય અથવા કેન્દ્રશાસિત પ્રદેશ તે સ્થળનું શ્રેષ્ઠ પ્રતિનિધિત્વ કરે છે જ્યાં તમે તમારા જીવનના નોંધપાત્ર ભાગ માટે રહ્યા છો?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q4, 'kn', 'ಭಾರತದಲ್ಲಿ ನಿಮ್ಮ ಜೀವನದ ಬಹುಪಾಲು ಕಳೆದಿರುವ ರಾಜ್ಯ ಅಥವಾ ಕೇಂದ್ರಾಡಳಿತ ಪ್ರದೇಶ ಯಾವುದು?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q4, 'ml', 'നിങ്ങളുടെ ജീവിതത്തിൻ്റെ ഒരു പ്രധാന ഭാഗം നിങ്ങൾ താമസിച്ചിരുന്ന സ്ഥലത്തെ ഏറ്റവും മികച്ച രീതിയിൽ പ്രതിനിധീകരിക്കുന്ന സംസ്ഥാനം അല്ലെങ്കിൽ കേന്ദ്രഭരണ പ്രദേശം ഏതാണ്?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q4, 'mr', 'भारतामधील कोणते राज्य किंवा केंद्रशासित प्रदेश तुमच्या जीवनाचा मोठा भाग दर्शवते?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q4, 'or', 'କେଉଁ ରାଜ୍ୟ କିମ୍ବା ୟୁନିଅନ୍ ଅଞ୍ଚଳ ସର୍ବୋତ୍ତମ ଭାବରେ ପ୍ରତିନିଧିତ୍ where କରେ ଯେଉଁଠାରେ ତୁମେ ତୁମର ଜୀବନର ଏକ ଗୁରୁତ୍ୱପୂର୍ଣ୍ଣ ଅଂଶ ପାଇଁ ବାସ କରିଛ?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q4, 'pa', 'ਕਿਹੜਾ ਰਾਜ ਜਾਂ ਕੇਂਦਰ ਸ਼ਾਸਿਤ ਪ੍ਰਦੇਸ਼ ਉਸ ਸਥਾਨ ਦੀ ਸਭ ਤੋਂ ਵਧੀਆ ਨੁਮਾਇੰਦਗੀ ਕਰਦਾ ਹੈ ਜਿੱਥੇ ਤੁਸੀਂ ਆਪਣੇ ਜੀਵਨ ਦੇ ਮਹੱਤਵਪੂਰਨ ਹਿੱਸੇ ਲਈ ਰਹੇ ਹੋ?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q4, 'ta', 'எந்த மாநிலம் அல்லது யூனியன் பிரதேசம் உங்கள் வாழ்க்கையின் குறிப்பிடத்தக்க பகுதியை நீங்கள் வாழ்ந்த இடத்தை சிறப்பாகக் குறிக்கிறது?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q4, 'te', 'మీ జీవితంలో ఎక్కువ భాగం గడిపిన రాష్ట్రం లేదా కేంద్ర పాలిత ప్రాంతం ఏది?');
