INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q18, 'en', 'Have you smoked cigarettes, bidis, or used any other form of tobacco (e.g., chewing tobacco)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q18, 'hi', 'क्या आपने सिगरेट, बीड़ी, या किसी अन्य प्रकार के तम्बाकू (जैसे चबाने वाला तम्बाकू) का उपयोग किया है?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q18, 'bn', 'আপনি কি সিগারেট, বিড়ি ধূমপান করেছেন বা অন্য কোন তামাক ব্যবহার করেছেন (যেমন, তামাক চিবানো)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q18, 'gu', 'શું તમે સિગારેટ, બીડી પીધી છે અથવા તમાકુના અન્ય કોઈપણ પ્રકારનો ઉપયોગ કર્યો છે (દા.ત., ચાવવાની તમાકુ)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q18, 'kn', 'ನೀವು ಎಂದಾದರೂ ಸಿಗರೆಟ್, ಬೀಡಿ ಅಥವಾ ತಂಬಾಕು ಉತ್ಪನ್ನಗಳನ್ನು (ಉದಾ., ಚಪ್ಪು ತಂಬಾಕು) ಬಳಸಿದ್ದೀರಾ?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q18, 'ml', 'നിങ്ങൾ സിഗരറ്റ്, ബീഡി, അല്ലെങ്കിൽ മറ്റേതെങ്കിലും തരത്തിലുള്ള പുകയില ഉപയോഗിച്ചിട്ടുണ്ടോ (ഉദാ. പുകയില ചവയ്ക്കുന്നത്)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q18, 'mr', 'तुम्ही कधी सिगारेट, बीडी किंवा तंबाखूच्या इतर कोणत्याही स्वरूपाचा (उदा., चघळायचा तंबाखू) वापर केला आहे का?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q18, 'or', 'ଆପଣ ସିଗାରେଟ୍, ବିଡିସ୍ ଧୂମପାନ କରିଛନ୍ତି କିମ୍ବା ଅନ୍ୟ କ form ଣସି ପ୍ରକାରର ତମାଖୁ ବ୍ୟବହାର କରିଛନ୍ତି (ଯଥା, ତମାଖୁ ଚୋବାଇବା)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q18, 'pa', 'ਕੀ ਤੁਸੀਂ ਸਿਗਰੇਟ, ਬੀੜੀਆਂ, ਜਾਂ ਤੰਬਾਕੂ ਦੇ ਕਿਸੇ ਹੋਰ ਰੂਪ ਦੀ ਵਰਤੋਂ ਕੀਤੀ ਹੈ (ਉਦਾਹਰਨ ਲਈ, ਚਬਾਉਣ ਵਾਲਾ ਤੰਬਾਕੂ)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q18, 'ta', 'நீங்கள் சிகரெட், பீடி புகைத்திருக்கிறீர்களா அல்லது வேறு ஏதேனும் புகையிலை/பாக்கு பயன்படுத்தியுள்ளீர்களா?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q18, 'te', 'మీరు ఎప్పుడైనా సిగరెట్లు, బీడీలు లేదా పొగాకు (ఉదా: నమలే పొగాకు) వాడారా?');
INSERT INTO question_options (question_id, option_value, sort_order) VALUES (@id_Q18, 'Yes', 0);
