INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q20, 'bn', 'কোনো আত্মীয়ের কি কোনো ধরনের ক্যান্সার ধরা পড়েছে?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q20, 'gu', 'શું કોઈ સંબંધીઓને કોઈપણ પ્રકારના કેન્સરનું નિદાન થયું છે?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q20, 'kn', 'ನಿಮ್ಮ ಕುಟುಂಬದ ಯಾವುದೇ ಸದಸ್ಯರಿಗೆ ಯಾವುದೇ ಪ್ರಕಾರದ ಕ್ಯಾನ್ಸರ್ ನಿರ್ಣಯ ಆಗಿದೆಯೆ?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q20, 'ml', 'ഏതെങ്കിലും തരത്തിലുള്ള ക്യാൻസർ ബാധിച്ചതായി ബന്ധുക്കൾ കണ്ടെത്തിയിട്ടുണ്ടോ?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q20, 'mr', 'तुमच्या कोणत्याही नातलगास कोणत्याही प्रकारच्या कर्करोगाचे निदान झाले आहे का?');
