INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q37, 'hi', 'यदि हाँ, कृपया बताएं आगे क्या सलाह दी गई थी:');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q37, 'bn', 'যদি হ্যাঁ, অনুগ্রহ করে উল্লেখ করুন পরবর্তীতে কী সুপারিশ করা হয়েছে:');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q37, 'gu', 'જો હા, તો કૃપા કરીને સ્પષ્ટ કરો કે આગળ શું ભલામણ કરવામાં આવી હતી:');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q37, 'kn', 'ಹೌದು ಎಂದಾದರೆ, ಮುಂದಿನ ಹಂತವಾಗಿ ಏನು ಮಾಡಲು ಶಿಫಾರಸು ಮಾಡಲಾಯಿತು?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q37, 'ml', 'അതെ എങ്കിൽ, അടുത്തതായി എന്താണ് ശുപാർശ ചെയ്തതെന്ന് വ്യക്തമാക്കുക:');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q37, 'mr', 'जर होय, तर पुढे कोणती तपासणी करण्याचा सल्ला देण्यात आला?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q37, 'or', 'ଯଦି ହଁ, ଦୟାକରି ପରବର୍ତ୍ତୀ ସମୟରେ ଯାହା ସୁପାରିଶ କରାଯାଇଥିଲା ତାହା ନିର୍ଦ୍ଦିଷ୍ଟ କରନ୍ତୁ:');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q37, 'pa', 'ਜੇਕਰ ਹਾਂ, ਤਾਂ ਕਿਰਪਾ ਕਰਕੇ ਦੱਸੋ ਕਿ ਅੱਗੇ ਕੀ ਸਿਫ਼ਾਰਸ਼ ਕੀਤੀ ਗਈ ਸੀ:');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q37, 'ta', 'ஆம் எனில், அடுத்து என்ன பரிந்துரைக்கப்பட்டது என்பதைக் குறிப்பிடவும்:');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q37, 'te', 'అవును అయితే, తదుపరి ఏ పరీక్షలు చేయమని సూచించారు?');
