INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q34, 'gu', 'શું તમે પરીક્ષા દરમિયાન સ્તન pAIn અથવા કોમળતાનો અનુભવ કર્યો હતો?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q34, 'kn', 'ಪರೀಕ್ಷೆಯ ಸಮಯದಲ್ಲಿ ಸ್ತನದಲ್ಲಿ ನೋವು ಅಥವಾ ಸೊಣತೆ ಅನುಭವಿಸಿದ್ದೀರಾ?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q34, 'ml', 'പരിശോധനയ്ക്കിടെ നിങ്ങൾക്ക് സ്തന pAIn അല്ലെങ്കിൽ ആർദ്രത അനുഭവപ്പെട്ടോ?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q34, 'mr', 'तपासणीदरम्यान तुम्हाला स्तनात वेदना किंवा कोमलता जाणवली का?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q34, 'or', 'ପରୀକ୍ଷା ସମୟରେ ଆପଣ ସ୍ତନ pAIn କିମ୍ବା କୋମଳତା ଅନୁଭବ କରିଛନ୍ତି କି?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q34, 'pa', 'ਕੀ ਤੁਸੀਂ ਜਾਂਚ ਦੌਰਾਨ ਛਾਤੀ pAIn ਜਾਂ ਕੋਮਲਤਾ ਦਾ ਅਨੁਭਵ ਕੀਤਾ ਸੀ?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q34, 'ta', 'பரிசோதனையின் போது மார்பகம் உள்ளே ஏதேனும் வலி அல்லது மென்மை ஏற்பட்டதா?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q34, 'te', 'పరీక్ష సమయంలో స్తన నొప్పి లేదా స్పర్శనీయత అనుభవించారా?');
