INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q35, 'en', 'If Yes, was it localized (one spot) or generalized (spread across a wider area)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q35, 'hi', 'यदि हाँ, क्या यह स्थानीय (एक जगह) था या सामान्यीकृत (एक विस्तृत क्षेत्र में फैला हुआ)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q35, 'bn', 'যদি হ্যাঁ, এটি কি স্থানীয়করণ (এক স্থান) বা সাধারণীকৃত (বিস্তৃত এলাকা জুড়ে ছড়িয়ে)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q35, 'gu', 'જો હા, તો શું તે સ્થાનિક (એક સ્થળ) અથવા સામાન્યકૃત (વિશાળ વિસ્તારમાં ફેલાયેલું) હતું?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q35, 'kn', 'ಹೌದು ಎಂದಾದರೆ, ನೋವು ಒಂದು ಸ್ಥಳಕ್ಕೆ ಸೀಮಿತವಾಗಿತ್ತೇ (ಸ್ಥಳೀಯ) ಅಥವಾ ಹೆಚ್ಚಿನ ಪ್ರದೇಶದಲ್ಲಿ ಹರಡಿತ್ತೇ (ಸಾಮಾನ್ಯ)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q35, 'ml', 'അതെ എങ്കിൽ, അത് പ്രാദേശികവൽക്കരിക്കപ്പെട്ടതാണോ (ഒരു സ്ഥലം) പൊതുവൽക്കരിക്കപ്പെട്ടതാണോ (വിശാലമായ ഒരു പ്രദേശത്ത് വ്യാപിച്ചിട്ടുണ്ടോ)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q35, 'mr', 'जर होय, तर ती वेदना एका ठिकाणी मर्यादित होती का (स्थानिक) किंवा मोठ्या भागात पसरलेली (सर्वसाधारण)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q35, 'or', 'ଯଦି ହଁ, ଏହା ଲୋକାଲାଇଜ୍ ହୋଇଥିଲା (ଗୋଟିଏ ସ୍ପଟ୍) କିମ୍ବା ସାଧାରଣକରଣ (ଏକ ବ୍ୟାପକ ଅଞ୍ଚଳରେ ବିସ୍ତାର)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q35, 'pa', 'ਜੇ ਹਾਂ, ਤਾਂ ਕੀ ਇਹ ਸਥਾਨਿਕ (ਇੱਕ ਥਾਂ) ਜਾਂ ਆਮ (ਵਿਆਪਕ ਖੇਤਰ ਵਿੱਚ ਫੈਲਿਆ) ਸੀ?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q35, 'ta', 'ஆம் எனில், அது உள்ளூர்மயமாக்கப்பட்டதா (ஒரு இடம்) அல்லது பொதுமைப்படுத்தப்பட்டதா (பரந்த பகுதியில் பரவியதா)?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q35, 'te', 'అవును అయితే, నొప్పి ఒక ప్రాంతానికే పరిమితమా లేక విస్తృతమా?');
