INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q42, 'bn', 'আপনি কি কখনো কোন ধরনের ক্যান্সারে আক্রান্ত হয়েছেন?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q42, 'gu', 'શું તમને ક્યારેય કોઈપણ પ્રકારના કેન્સરનું નિદાન થયું છે?');
