INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q42, 'ml', 'നിങ്ങൾക്ക് എപ്പോഴെങ്കിലും ഏതെങ്കിലും തരത്തിലുള്ള ക്യാൻസർ ഉണ്ടെന്ന് കണ്ടെത്തിയിട്ടുണ്ടോ?');
INSERT INTO question_translations (question_id, language_code, question_text) VALUES (@id_Q42, 'mr', 'तुम्हाला कधी कोणत्याही प्रकारच्या कर्करोगाचे निदान झाले आहे का?');
